import{_ as a,c as r,o as e,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"429トラブルシューティング: アカウントローテーションとエラー処理 | Antigravity-Manager","description":"Antigravity Tools の 429 エラートラブルシューティング方法を学びます。QUOTA_EXHAUSTED、RATE_LIMIT_EXCEEDED などのエラーの識別と処理をマスターし、Monitor と X-Account-Email を使って問題を素早く特定します。","frontmatter":{"title":"429トラブルシューティング: アカウントローテーションとエラー処理 | Antigravity-Manager","sidebarTitle":"429エラー：自動ローテーション","subtitle":"429トラブルシューティング: アカウントローテーションとエラー処理","description":"Antigravity Tools の 429 エラートラブルシューティング方法を学びます。QUOTA_EXHAUSTED、RATE_LIMIT_EXCEEDED などのエラーの識別と処理をマスターし、Monitor と X-Account-Email を使って問題を素早く特定します。","tags":["FAQ","エラートラブルシューティング","アカウントスケジューリング","429エラー"],"prerequisite":["start-getting-started","advanced-scheduling"],"order":3},"headers":[],"relativePath":"ja/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md","filePath":"ja/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md"}'),i={name:"ja/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md"};function s(l,t,n,d,c,p){return e(),r("div",null,[...t[0]||(t[0]=[o(`<h1 id="_429-容量エラー-アカウントローテーションの正しい期待とモデル容量枯渇の誤解" tabindex="-1">429/容量エラー：アカウントローテーションの正しい期待とモデル容量枯渇の誤解 <a class="header-anchor" href="#_429-容量エラー-アカウントローテーションの正しい期待とモデル容量枯渇の誤解" aria-label="Permalink to &quot;429/容量エラー：アカウントローテーションの正しい期待とモデル容量枯渇の誤解&quot;">​</a></h1><h2 id="学んだ後できること" tabindex="-1">学んだ後できること <a class="header-anchor" href="#学んだ後できること" aria-label="Permalink to &quot;学んだ後できること&quot;">​</a></h2><ul><li>「クォータ不足」と「アップストリームレート制限」を正しく区別し、誤判を避けられる</li><li>Antigravity Tools の自動ローテーションメカニズムと期待される動作を理解できる</li><li>429 エラーに遭遇したとき、問題を素早く特定し、設定を最適化できる</li></ul><h2 id="現在の悩み" tabindex="-1">現在の悩み <a class="header-anchor" href="#現在の悩み" aria-label="Permalink to &quot;現在の悩み&quot;">​</a></h2><ul><li>429 エラーが返ってくると、誤って「モデルに容量がない」と思う</li><li>複数のアカウントを設定しているのに、依然として頻繁に 429 に遭遇し、設定問題かアカウント問題かわからない</li><li>システムがいつ自動的にアカウントを切り替えるのか、いつ「詰まる」のかが不明確</li></ul><h2 id="コアコンセプト" tabindex="-1">コアコンセプト <a class="header-anchor" href="#コアコンセプト" aria-label="Permalink to &quot;コアコンセプト&quot;">​</a></h2><h3 id="_429-エラーとは" tabindex="-1">429 エラーとは？ <a class="header-anchor" href="#_429-エラーとは" aria-label="Permalink to &quot;429 エラーとは？&quot;">​</a></h3><p><strong>429 Too Many Requests</strong> は HTTP ステータスコードです。Antigravity Tools では、429 は「リクエストが多すぎる」だけでなく、クォータ枯渇、モデルの一時的な過負荷など「あなたが一時的に使用できない」信号のカテゴリを表します。</p><div class="info custom-block"><p class="custom-block-title">プロキシは 429 の原因を識別しようとします</p><p>プロキシはレスポンスボディから <code>error.details[0].reason</code> または <code>error.message</code> を解析し、429 を大まかにいくつかのタイプに分けます（実際は返り値に依存します）：</p><table tabindex="0"><thead><tr><th>プロキシ識別タイプ</th><th>一般的な reason / 手がかり</th><th>典型的な特徴</th></tr></thead><tbody><tr><td><strong>クォータ枯渇</strong></td><td><code>QUOTA_EXHAUSTED</code> / テキストに <code>exhausted</code>、<code>quota</code> を含む</td><td>クォータが更新されるまで待つ必要がある可能性</td></tr><tr><td><strong>レート制限</strong></td><td><code>RATE_LIMIT_EXCEEDED</code> / テキストに <code>per minute</code>、<code>rate limit</code>、<code>too many requests</code> を含む</td><td>通常は数十秒レベルのクールダウン</td></tr><tr><td><strong>モデル容量不足</strong></td><td><code>MODEL_CAPACITY_EXHAUSTED</code> / テキストに <code>model_capacity</code> を含む</td><td>一般的には一時的な過負荷で、後で回復可能</td></tr><tr><td><strong>不明</strong></td><td>解析不能</td><td>デフォルトクールダウン戦略に従う</td></tr></tbody></table></div><h3 id="antigravity-tools-の自動処理" tabindex="-1">Antigravity Tools の自動処理 <a class="header-anchor" href="#antigravity-tools-の自動処理" aria-label="Permalink to &quot;Antigravity Tools の自動処理&quot;">​</a></h3><p>一回のリクエストで 429（および一部の 5xx/過負荷状態）に遭遇したとき、プロキシは通常サーバー側で 2 つのことを行います：</p><ol><li><strong>クールダウン時間を記録</strong>：このエラーを <code>RateLimitTracker</code> に書き込み、後続のアカウント選択時に「まだクールダウン中」のアカウントを積極的に回避する</li><li><strong>再試行内でアカウントをローテーション</strong>：Handlers は単一リクエスト内で複数回の試行を行い、再試行時に <code>force_rotate=true</code> となり、TokenManager が次の利用可能なアカウントを選択するようにトリガーする</li></ol><div class="tip custom-block"><p class="custom-block-title">アカウントを切り替えたかどうかをどう知るか</p><p>リクエストボディが変わらなくても、レスポンスには通常 <code>X-Account-Email</code>（および <code>X-Mapped-Model</code>）が含まれます。これを使って「今回のリクエストがどのアカウントを使ったか」を検証できます。</p></div><h2 id="いつ-429-エラーに遭遇するか" tabindex="-1">いつ 429 エラーに遭遇するか <a class="header-anchor" href="#いつ-429-エラーに遭遇するか" aria-label="Permalink to &quot;いつ 429 エラーに遭遇するか&quot;">​</a></h2><h3 id="シナリオ-1-単一アカウントでリクエストが速すぎる" tabindex="-1">シナリオ 1：単一アカウントでリクエストが速すぎる <a class="header-anchor" href="#シナリオ-1-単一アカウントでリクエストが速すぎる" aria-label="Permalink to &quot;シナリオ 1：単一アカウントでリクエストが速すぎる&quot;">​</a></h3><p><strong>現象</strong>：アカウントが 1 つだけでも、短時間に大量のリクエストを送ると 429 がトリガーされる</p><p><strong>原因</strong>：各アカウントには独自のレート制限（RPM/TPM）があり、超えると制限される</p><p><strong>解決</strong>：</p><ul><li>アカウント数を増やす</li><li>リクエスト頻度を下げる</li><li>固定アカウントモードを使って分散させる（「固定アカウントモード」を参照）</li></ul><h3 id="シナリオ-2-すべてのアカウントが同時にレート制限される" tabindex="-1">シナリオ 2：すべてのアカウントが同時にレート制限される <a class="header-anchor" href="#シナリオ-2-すべてのアカウントが同時にレート制限される" aria-label="Permalink to &quot;シナリオ 2：すべてのアカウントが同時にレート制限される&quot;">​</a></h3><p><strong>現象</strong>：複数のアカウントがあるのに、すべてのアカウントが 429 を返す</p><p><strong>原因</strong>：</p><ul><li>アカウント総数があなたのリクエスト頻度を支えるのに不十分</li><li>すべてのアカウントがほぼ同時にレート制限/過負荷をトリガーした</li></ul><p><strong>解決</strong>：</p><ul><li>さらにアカウントを追加</li><li>スケジューリングモードを「パフォーマンス優先」に調整（スティッキーセッションと 60 秒ウィンドウ再利用をスキップ）</li><li>クォータ保護が利用可能なアカウントを誤って除外していないか確認</li></ul><h3 id="シナリオ-3-アカウントがクォータ保護で誤判定される" tabindex="-1">シナリオ 3：アカウントがクォータ保護で誤判定される <a class="header-anchor" href="#シナリオ-3-アカウントがクォータ保護で誤判定される" aria-label="Permalink to &quot;シナリオ 3：アカウントがクォータ保護で誤判定される&quot;">​</a></h3><p><strong>現象</strong>：あるアカウントのクォータは十分にあるのに、システムがずっとそれをスキップする</p><p><strong>原因</strong>：</p><ul><li><strong>クォータ保護</strong>が有効で、閾値が高すぎる</li><li>そのアカウントの特定モデルクォータが閾値より低い</li><li>アカウントが手動で <code>proxy_disabled</code> とマークされている</li></ul><p><strong>解決</strong>：</p><ul><li>クォータ保護設定を確認（Settings → Quota Protection）、使用強度に応じて閾値と監視モデルを調整</li><li>アカウントデータで <code>protected_models</code> を確認し、保護戦略でスキップされているか確認</li></ul><h2 id="手順通りに進める" tabindex="-1">手順通りに進める <a class="header-anchor" href="#手順通りに進める" aria-label="Permalink to &quot;手順通りに進める&quot;">​</a></h2><h3 id="第-1-ステップ-429-エラータイプを識別" tabindex="-1">第 1 ステップ：429 エラータイプを識別 <a class="header-anchor" href="#第-1-ステップ-429-エラータイプを識別" aria-label="Permalink to &quot;第 1 ステップ：429 エラータイプを識別&quot;">​</a></h3><p><strong>なぜか</strong>：異なるタイプの 429 エラーは異なる処理方法が必要</p><p>Proxy Monitor で 429 エラーのレスポンスボディを確認し、2 種類の情報に焦点を当てる：</p><ul><li><strong>原因</strong>：<code>error.details[0].reason</code>（例：<code>RATE_LIMIT_EXCEEDED</code>、<code>QUOTA_EXHAUSTED</code>）または <code>error.message</code></li><li><strong>待ち時間</strong>：<code>RetryInfo.retryDelay</code> または <code>details[0].metadata.quotaResetDelay</code>（存在する場合）</li></ul><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;details&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;RATE_LIMIT_EXCEEDED&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;metadata&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">          &quot;quotaResetDelay&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;42s&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>表示されるべきもの</strong>：</p><ul><li>レスポンスボディに待ち時間が見つかる場合（例：<code>RetryInfo.retryDelay</code> または <code>quotaResetDelay</code>）、プロキシは通常しばらく待ってから再試行します</li><li>待ち時間がない場合、プロキシは組み込み戦略に従ってそのアカウントに「クールダウン期間」を追加し、再試行時に直接次のアカウントに切り替えます</li></ul><h3 id="第-2-ステップ-アカウントスケジューリング設定を確認" tabindex="-1">第 2 ステップ：アカウントスケジューリング設定を確認 <a class="header-anchor" href="#第-2-ステップ-アカウントスケジューリング設定を確認" aria-label="Permalink to &quot;第 2 ステップ：アカウントスケジューリング設定を確認&quot;">​</a></h3><p><strong>なぜか</strong>：スケジューリング設定はアカウントローテーション頻度と優先度に直接影響します</p><p><strong>API Proxy</strong> ページに入り、スケジューリング戦略を確認：</p><table tabindex="0"><thead><tr><th>設定項目</th><th>説明</th><th>デフォルト/推奨</th></tr></thead><tbody><tr><td><strong>Scheduling Mode</strong></td><td>スケジューリングモード</td><td><code>Balance</code>（デフォルト）</td></tr><tr><td><strong>Preferred Account</strong></td><td>固定アカウントモード</td><td>未選択（デフォルト）</td></tr></tbody></table><p><strong>スケジューリングモード比較</strong>：</p><table tabindex="0"><thead><tr><th>モード</th><th>アカウント再利用戦略</th><th>レート制限処理</th><th>適用シナリオ</th></tr></thead><tbody><tr><td><strong>CacheFirst</strong></td><td>スティッキーセッションと 60 秒ウィンドウ再利用を有効</td><td><strong>優先的に待機</strong>、Prompt Caching ヒット率を大幅に向上</td><td>会話型/高キャッシュヒット率が必要</td></tr><tr><td><strong>Balance</strong></td><td>スティッキーセッションと 60 秒ウィンドウ再利用を有効</td><td><strong>直ちに切り替え</strong>て代替アカウント、成功率とパフォーマンスを両立</td><td>一般的なシナリオ、デフォルト</td></tr><tr><td><strong>PerformanceFirst</strong></td><td>スティッキーセッションと 60 秒ウィンドウ再利用をスキップ、純粋なラウンドロビンモード</td><td>直ちに切り替え、アカウント負荷が最も均等</td><td>高並列、ステートレスリクエスト</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">キャッシュ優先 vs バランスモード</p><p>Prompt Caching を使用していてキャッシュヒット率を上げたい場合、<code>CacheFirst</code> を選択してください — レート制限時に優先的に待機してすぐにアカウントを切り替えません。成功率をキャッシュより重視する場合、<code>Balance</code> を選択してください — レート制限時にすぐにアカウントを切り替えます。</p></div><div class="tip custom-block"><p class="custom-block-title">パフォーマンス優先モード</p><p>リクエストがステートレス（画像生成、独立クエリなど）の場合、<code>PerformanceFirst</code> を試してください。スティッキーセッションと 60 秒ウィンドウ再利用をスキップし、連続リクエストが異なるアカウントに落ちやすくします。</p></div><h3 id="第-3-ステップ-アカウントローテーションが正常に動作しているか検証" tabindex="-1">第 3 ステップ：アカウントローテーションが正常に動作しているか検証 <a class="header-anchor" href="#第-3-ステップ-アカウントローテーションが正常に動作しているか検証" aria-label="Permalink to &quot;第 3 ステップ：アカウントローテーションが正常に動作しているか検証&quot;">​</a></h3><p><strong>なぜか</strong>：システムが自動的にアカウントを切り替えられることを確認</p><p><strong>方法 1：レスポンスヘッダーを見る</strong></p><p>curl または自分のクライアントでレスポンスヘッダーを印刷し、<code>X-Account-Email</code> が変化するか観察</p><p><strong>方法 2：ログを確認</strong></p><p>ログファイル（システムの場所に応じて）を開き、<code>🔄 [Token Rotation]</code> を検索：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔄 [Token Rotation] Accounts: [</span></span>
<span class="line"><span>  &quot;account1@example.com(protected=[])&quot;,</span></span>
<span class="line"><span>  &quot;account2@example.com(protected=[])&quot;,</span></span>
<span class="line"><span>  &quot;account3@example.com(protected=[])&quot;</span></span>
<span class="line"><span>]</span></span></code></pre></div><p><strong>方法 3：Proxy Monitor を使用</strong></p><p><strong>Monitor</strong> ページでリクエストログを確認し、以下に注目：</p><ul><li><strong>Account</strong> フィールドが異なるアカウント間で切り替わっているか</li><li><strong>Status</strong> が 429 のリクエストの後、異なるアカウントを使った成功したリクエストがあるか</li></ul><p><strong>表示されるべきもの</strong>：</p><ul><li>あるアカウントが 429 を返した後、後続リクエストが自動的に他のアカウントに切り替わる</li><li>複数のリクエストが同じアカウントを使ってすべて失敗している場合、スケジューリング設定の問題の可能性がある</li></ul><h3 id="第-4-ステップ-アカウント優先度を最適化" tabindex="-1">第 4 ステップ：アカウント優先度を最適化 <a class="header-anchor" href="#第-4-ステップ-アカウント優先度を最適化" aria-label="Permalink to &quot;第 4 ステップ：アカウント優先度を最適化&quot;">​</a></h3><p><strong>なぜか</strong>：システムが優先的に高クォータ/高ランクアカウントを使うようにし、429 確率を減らす</p><p>TokenManager では、アカウント選択前にアカウントプールを一度ソートします（<code>🔄 [Token Rotation] Accounts: ...</code> と印刷されます）：</p><ol><li><strong>サブスクリプションランク優先</strong>：ULTRA &gt; PRO &gt; FREE</li><li><strong>クォータパーセンテージ優先</strong>：同ランク内で、クォータが高いものが前</li><li><strong>ソートエントリー</strong>：このソートはプロキシ側で行われ、最終的にどのアカウントを使うかはプロキシ側ソート + 可用性判断が基準</li></ol><div class="info custom-block"><p class="custom-block-title">インテリジェントソート原理（プロキシ側）</p><p>優先度は <code>ULTRA &gt; PRO &gt; FREE</code>；同一サブスクリプションランク内では <code>remaining_quota</code>（アカウント最大残りクォータパーセンテージ）降順。</p></div><p><strong>操作</strong>：</p><ul><li>アカウントをドラッグして表示順序を調整（オプション）</li><li>クォータをリフレッシュ（Accounts → すべてのクォータをリフレッシュ）</li><li>アカウントのサブスクリプションランクとクォータを確認</li></ul><h2 id="罠の警告" tabindex="-1">罠の警告 <a class="header-anchor" href="#罠の警告" aria-label="Permalink to &quot;罠の警告&quot;">​</a></h2><h3 id="❌-間違い-1-429-を「モデルに容量がない」と誤解" tabindex="-1">❌ 間違い 1：429 を「モデルに容量がない」と誤解 <a class="header-anchor" href="#❌-間違い-1-429-を「モデルに容量がない」と誤解" aria-label="Permalink to &quot;❌ 間違い 1：429 を「モデルに容量がない」と誤解&quot;">​</a></h3><p><strong>現象</strong>：429 エラーを見ると、モデルに容量がないと思う</p><p><strong>正しい理解</strong>：</p><ul><li>429 は<strong>レート制限</strong>で、容量問題ではない</li><li>アカウントを増やすと 429 確率を下げられる</li><li>スケジューリングモードを調整すると切り替え速度を上げられる</li></ul><h3 id="❌-間違い-2-クォータ保護閾値を高すぎる" tabindex="-1">❌ 間違い 2：クォータ保護閾値を高すぎる <a class="header-anchor" href="#❌-間違い-2-クォータ保護閾値を高すぎる" aria-label="Permalink to &quot;❌ 間違い 2：クォータ保護閾値を高すぎる&quot;">​</a></h3><p><strong>現象</strong>：クォータは十分なのに、システムがずっとアカウントをスキップする</p><p><strong>原因</strong>：Quota Protection は閾値より低いモデルをアカウントの <code>protected_models</code> に追加し、プロキシはスケジューリング時に「保護されたモデル」をスキップします。閾値が高すぎると、利用可能なアカウントが過度に除外される可能性があります。</p><p><strong>修正</strong>：</p><ul><li><strong>Settings → Quota Protection</strong> に戻り、監視モデルと閾値を調整</li><li>どのモデルが保護されたのかをはっきりさせたい場合、アカウントデータで <code>protected_models</code> を見る</li></ul><h3 id="❌-間違い-3-固定アカウントモードでローテーションできない" tabindex="-1">❌ 間違い 3：固定アカウントモードでローテーションできない <a class="header-anchor" href="#❌-間違い-3-固定アカウントモードでローテーションできない" aria-label="Permalink to &quot;❌ 間違い 3：固定アカウントモードでローテーションできない&quot;">​</a></h3><p><strong>現象</strong>：<code>Preferred Account</code> を設定したが、そのアカウントがレート制限されるとシステムが「詰まる」</p><p><strong>原因</strong>：固定アカウントモードでは、システムは指定アカウントを優先的に使用し、アカウントが利用不可の場合のみラウンドロビンにダウングレードします。</p><p><strong>修正</strong>：</p><ul><li>固定アカウントが必要ない場合、<code>Preferred Account</code> をクリア</li><li>または固定アカウントのクォータが十分であることを確認し、レート制限を避ける</li></ul><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><ul><li>[ ] クォータ不足とアップストリームレート制限を区別できる</li><li>[ ] Proxy Monitor で 429 エラー詳細を確認する方法を知っている</li><li>[ ] 3 つのスケジューリングモードの違いと適用シナリオを理解している</li><li>[ ] アカウントローテーションが正常に動作しているか確認する方法を知っている</li><li>[ ] アカウント優先度を最適化し、クォータ保護戦略を確認できる</li></ul><h2 id="よくある質問" tabindex="-1">よくある質問 <a class="header-anchor" href="#よくある質問" aria-label="Permalink to &quot;よくある質問&quot;">​</a></h2><h3 id="q1-複数のアカウントがあるのに、依然として-429-に遭遇するのはなぜ" tabindex="-1">Q1：複数のアカウントがあるのに、依然として 429 に遭遇するのはなぜ？ <a class="header-anchor" href="#q1-複数のアカウントがあるのに、依然として-429-に遭遇するのはなぜ" aria-label="Permalink to &quot;Q1：複数のアカウントがあるのに、依然として 429 に遭遇するのはなぜ？&quot;">​</a></h3><p>A：可能な原因：</p><ol><li>すべてのアカウントが同時にレート制限をトリガー（リクエスト頻度が高すぎる）</li><li>連続リクエストが「60 秒ウィンドウ再利用」で同じアカウントを繰り返し再利用し、単一アカウントをレート制限に打ち込みやすい</li><li>クォータ保護が利用可能なアカウントを誤って除外</li><li>アカウント総数があなたのリクエスト頻度を支えるのに不十分</li></ol><p><strong>解決</strong>：</p><ul><li>さらにアカウントを追加</li><li><code>PerformanceFirst</code> モードを使用</li><li>Quota Protection があなたが使いたいモデルを <code>protected_models</code> に追加していないか確認（必要なら監視モデルと閾値を調整）</li><li>リクエスト頻度を下げる</li></ul><h3 id="q2-429-エラーは自動的に再試行されますか" tabindex="-1">Q2：429 エラーは自動的に再試行されますか？ <a class="header-anchor" href="#q2-429-エラーは自動的に再試行されますか" aria-label="Permalink to &quot;Q2：429 エラーは自動的に再試行されますか？&quot;">​</a></h3><p>A：単一リクエスト内で自動再試行されます。<strong>再試行回数の上限は通常 3 回</strong>で、具体的な計算方法は <code>min(3, アカウントプールサイズ)</code> であり、少なくとも 1 回試行します。</p><p><strong>再試行回数の例</strong>：</p><ul><li>アカウントプール 1 アカウント → 1 回試行（再試行なし）</li><li>アカウントプール 2 アカウント → 2 回試行（再試行 1 回）</li><li>アカウントプール 3 つ以上のアカウント → 3 回試行（再試行 2 回）</li></ul><p><strong>大まかな流れ</strong>：</p><ol><li>レート制限/過負荷情報を記録（<code>RateLimitTracker</code> に進入）</li><li>待ち時間を解析できる場合（例：<code>RetryInfo.retryDelay</code> / <code>quotaResetDelay</code>）、しばらく待ってから続行</li><li>再試行時に強制的にアカウントをローテーション（<code>attempt &gt; 0</code> の時 <code>force_rotate=true</code>）、次の利用可能なアカウントでアップストリームリクエストを試行</li></ol><p>すべての試行が失敗すると、プロキシはエラーをクライアントに返します。同時に、レスポンスヘッダー（例：<code>X-Account-Email</code>）または Proxy Monitor から実際に使用されたアカウントを確認できます。</p><h3 id="q3-あるアカウントがどのくらいレート制限されているか確認するには" tabindex="-1">Q3：あるアカウントがどのくらいレート制限されているか確認するには？ <a class="header-anchor" href="#q3-あるアカウントがどのくらいレート制限されているか確認するには" aria-label="Permalink to &quot;Q3：あるアカウントがどのくらいレート制限されているか確認するには？&quot;">​</a></h3><p>A：2 つの方法があります：</p><p><strong>方法 1</strong>：ログを確認し、<code>rate-limited</code> を検索</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔒 [FIX #820] Preferred account xxx@gmail.com is rate-limited, falling back to round-robin</span></span></code></pre></div><p><strong>方法 2</strong>：ログに残り待ち時間が表示されます</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>All accounts are currently limited. Please wait 30s.</span></span></code></pre></div><h3 id="q4-クォータ保護とレート制限は同じですか" tabindex="-1">Q4：クォータ保護とレート制限は同じですか？ <a class="header-anchor" href="#q4-クォータ保護とレート制限は同じですか" aria-label="Permalink to &quot;Q4：クォータ保護とレート制限は同じですか？&quot;">​</a></h3><p>A：違います。</p><table tabindex="0"><thead><tr><th>特性</th><th>クォータ保護</th><th>レート制限追跡</th></tr></thead><tbody><tr><td><strong>トリガー条件</strong></td><td>モデルクォータが閾値より低い</td><td>429 エラーを受信</td></tr><tr><td><strong>適用範囲</strong></td><td>特定のモデル</td><td>アカウント全体</td></tr><tr><td><strong>持続時間</strong></td><td>クォータが回復するまで</td><td>アップストリームが決定（通常数秒から数分）</td></tr><tr><td><strong>動作</strong></td><td>そのモデルをスキップ</td><td>そのアカウントをスキップ</td></tr></tbody></table><h3 id="q5-どのようにしてすぐにアカウントを切り替えることを強制できますか" tabindex="-1">Q5：どのようにしてすぐにアカウントを切り替えることを強制できますか？ <a class="header-anchor" href="#q5-どのようにしてすぐにアカウントを切り替えることを強制できますか" aria-label="Permalink to &quot;Q5：どのようにしてすぐにアカウントを切り替えることを強制できますか？&quot;">​</a></h3><p>A：「次回リクエストがアカウントを切り替えやすくする」という観点から着手できます：</p><ol><li><strong>スケジューリング層</strong>：<code>PerformanceFirst</code> に切り替え、スティッキーセッションと 60 秒ウィンドウ再利用をスキップ</li><li><strong>固定アカウント</strong>：<code>Preferred Account</code> が有効の場合、先にクリア。そうしないと優先的に固定アカウントを使う（レート制限/保護されるまで）</li><li><strong>アカウントプール</strong>：アカウント数を増やし、単一アカウントがレート制限されたときに代替アカウントを見つけやすくする</li></ol><p>単一リクエスト内では、プロキシ自体も再試行時に強制的にローテーションします（<code>attempt &gt; 0</code> は <code>force_rotate=true</code> をトリガー）、ただし再試行回数は上限制御を受けます。</p><h2 id="レッスンまとめ" tabindex="-1">レッスンまとめ <a class="header-anchor" href="#レッスンまとめ" aria-label="Permalink to &quot;レッスンまとめ&quot;">​</a></h2><ul><li>429 は Antigravity Tools では「アップストリームが一時的に利用不可」の信号のカテゴリであり、レート制限、クォータ枯渇、モデル容量不足などが原因の可能性がある</li><li>プロキシはクールダウン時間を記録し、単一リクエストの再試行でアカウントローテーションを試みる（ただし再試行回数は限定的）</li><li>スケジューリングモード、Quota Protection、アカウント数はすべてあなたが遭遇する 429 の確率と回復速度に影響する</li><li>Proxy Monitor、レスポンスヘッダー <code>X-Account-Email</code> とログを使って問題を素早く特定できる</li></ul><h2 id="次のレッスン予告" tabindex="-1">次のレッスン予告 <a class="header-anchor" href="#次のレッスン予告" aria-label="Permalink to &quot;次のレッスン予告&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="./../404-base-url/">404/パス互換性：Base URL、/v1 プレフィックスと「重なりパス」クライアント</a></strong> を学びます</p><p>学べること：</p><ul><li>最も一般的な接続エラー（404）がどのように発生するか</li><li>異なるクライアントの base_url 連結の違い</li><li>404 問題を素早く修正する方法</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を展開</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>429 再試行遅延解析（RetryInfo / quotaResetDelay）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/upstream/retry.rs#L38-L67" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/upstream/retry.rs</code></a></td><td>38-67</td></tr><tr><td>Duration 解析ツール</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/upstream/retry.rs#L11-L35" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/upstream/retry.rs</code></a></td><td>11-35</td></tr><tr><td>スケジューリングモード列挙（CacheFirst/Balance/PerformanceFirst）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/sticky_config.rs#L3-L12" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/sticky_config.rs</code></a></td><td>3-12</td></tr><tr><td>レート制限原因解析とデフォルトクールダウン戦略</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/rate_limit.rs#L5-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/rate_limit.rs</code></a></td><td>5-258</td></tr><tr><td>MAX_RETRY_ATTEMPTS 定数定義（OpenAI handler）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L14" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>14</td></tr><tr><td>再試行回数計算（max_attempts = min(MAX_RETRY_ATTEMPTS, pool_size)）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L830" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>830</td></tr><tr><td>OpenAI handler：429/5xx 時にレート制限をマークし再試行/ローテーション</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L349-L389" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>349-389</td></tr><tr><td>アカウントソート優先度（ULTRA &gt; PRO &gt; FREE + remaining_quota）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L504-L538" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>504-538</td></tr><tr><td>60 秒ウィンドウ再利用 + レート制限/クォータ保護回避</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L624-L739" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>624-739</td></tr><tr><td>レート制限記録エントリー（mark_rate_limited）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1089-L1113" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1089-1113</td></tr><tr><td>429 精密ロック/リアルタイムクォータリフレッシュ/ダウングレード戦略（mark_rate_limited_async）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1258-L1417" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1258-1417</td></tr></tbody></table><p><strong>重要な定数</strong>：</p><ul><li><code>MAX_RETRY_ATTEMPTS = 3</code>：単一リクエスト内最大再試行回数（OpenAI/Gemini handler）</li><li><code>60</code>：60 秒ウィンドウ再利用（<code>PerformanceFirst</code> 以外のモードでのみ有効）</li><li><code>5</code>：Token 取得タイムアウト時間（秒）</li><li><code>300</code>：Token 事前リフレッシュ閾値（秒、5 分）</li></ul><p><strong>重要な関数</strong>：</p><ul><li><code>parse_retry_delay()</code>：429 エラーレスポンスから再試行遅延を抽出</li><li><code>get_token_internal()</code>：アカウント選択とローテーションのコアロジック</li><li><code>mark_rate_limited()</code>：アカウントをレート制限状態にマーク</li></ul></details>`,116)])])}const u=a(i,[["render",s]]);export{g as __pageData,u as default};
